// Extract job IDs from GraphQL JobRecommendations response
const items = [];
const input = $input.first().json;
const dateReceived = new Date().toISOString().split('T')[0];

// Check for auth errors
if (!input.data || !input.data.currentUser) {
  const errorMsg = input.errors
    ? input.errors.map(e => e.message).join('; ')
    : 'currentUser is null — session expired';
  items.push({
    json: {
      _error: true,
      externalId: '__AUTH_ERROR__',
      'Date Received': dateReceived,
      'Company': '⚠ AUTH ERROR',
      'Job Title': 'WTTJ session expired — refresh WTTJ_COOKIE and WTTJ_CSRF_TOKEN in .env',
      'URL': '',
      'Location': '',
      'Remote': '',
      'Salary': '',
      'Experience': '',
      'Technologies': '',
      'Function': '',
      'Company Size': '',
      'Funding': '',
      'Status': 'AUTH_EXPIRED',
      'Source': 'graphql'
    }
  });
  return items;
}

const recommendations = input.data.currentUser.jobRecommendations || [];

if (recommendations.length === 0) {
  items.push({
    json: {
      _error: true,
      externalId: '__EMPTY__',
      'Date Received': dateReceived,
      'Company': '⚠ NO RECOMMENDATIONS',
      'Job Title': 'No job recommendations returned',
      'URL': '',
      'Location': '',
      'Remote': '',
      'Salary': '',
      'Experience': '',
      'Technologies': '',
      'Function': '',
      'Company Size': '',
      'Funding': '',
      'Status': 'Error',
      'Source': 'graphql'
    }
  });
  return items;
}

for (const rec of recommendations) {
  const job = rec.job;
  items.push({
    json: {
      externalId: job.externalId,
      title: job.title,
      company: job.company.name,
      dateReceived
    }
  });
}

return items;

// Parse job details from GraphQL response and classify by location
const DMV_KEYWORDS = [
  'washington', 'dc', 'd.c.', 'district of columbia',
  'maryland', 'virginia',
  'arlington', 'alexandria', 'fairfax', 'reston', 'tysons',
  'mclean', 'herndon', 'sterling', 'ashburn', 'leesburg',
  'bethesda', 'rockville', 'silver spring', 'college park',
  'columbia', 'baltimore', 'annapolis', 'dmv'
];

const REMOTE_KEYWORDS = [
  'remote', 'full remote', 'full-remote', 'fully remote',
  'work from home', 'wfh', 'anywhere', 'distributed'
];

function classifyLocation(locationStr, isRemote) {
  if (isRemote) return 'Relevant';
  if (!locationStr) return 'Skip';
  const loc = locationStr.toLowerCase();
  for (const kw of REMOTE_KEYWORDS) {
    if (loc.includes(kw)) return 'Relevant';
  }
  for (const kw of DMV_KEYWORDS) {
    if (loc.includes(kw)) return 'Relevant';
  }
  return 'Skip';
}

const items = [];
const dateReceived = new Date().toISOString().split('T')[0];
const extractItems = $('Extract Job IDs').all();

for (let i = 0; i < $input.all().length; i++) {
  const extractItem = extractItems[i]?.json || {};

  // If this was an error from Extract Job IDs, pass through
  if (extractItem._error) {
    const { _error, externalId, ...rest } = extractItem;
    items.push({ json: { ...rest, 'Job ID': '', 'Apply URL': '', 'Progress': '', 'Applied': '' } });
    continue;
  }

  const json = $input.all()[i].json;
  const job = json.data?.publicJob;

  if (!job) {
    const errorMsg = json.errors
      ? json.errors.map(e => e.message).join('; ')
      : 'Job not found';
    items.push({
      json: {
        'Date Received': dateReceived,
        'Company': extractItem.company || '⚠ FETCH ERROR',
        'Job Title': extractItem.title || errorMsg,
        'URL': '',
        'Location': '',
        'Remote': '',
        'Salary': '',
        'Experience': '',
        'Technologies': '',
        'Function': '',
        'Company Size': '',
        'Funding': '',
        'Status': 'Error',
        'Source': 'graphql',
        'Job ID': '',
        'Apply URL': '',
        'Progress': '',
        'Applied': ''
      }
    });
    continue;
  }

  // Format salary
  let salary = '';
  if (job.salaryRange) {
    const { minAmount, maxAmount, currency } = job.salaryRange;
    const fmt = (n) => {
      const num = parseInt(n);
      return num >= 1000 ? `${Math.round(num / 1000)}K` : num;
    };
    if (minAmount && maxAmount) {
      salary = `${currency} ${fmt(minAmount)}\u2013${fmt(maxAmount)}`;
    } else if (minAmount) {
      salary = `${currency} ${fmt(minAmount)}+`;
    } else if (maxAmount) {
      salary = `Up to ${currency} ${fmt(maxAmount)}`;
    }
  }

  // Format location
  const locations = (job.formattedLocationPreferences || [])
    .map(l => l.name)
    .join(', ');

  // Format experience
  let experience = '';
  if (job.minYearsExperienceRequired != null && job.maxYearsExperienceRequired != null) {
    experience = `${job.minYearsExperienceRequired}\u2013${job.maxYearsExperienceRequired} years`;
  } else if (job.minYearsExperienceRequired != null) {
    experience = `${job.minYearsExperienceRequired}+ years`;
  } else if (job.maxYearsExperienceRequired != null) {
    experience = `Up to ${job.maxYearsExperienceRequired} years`;
  }

  // Format technologies
  const technologies = (job.technologiesUsed || [])
    .map(t => t.value)
    .join(', ');

  // Company info
  const co = job.company || {};
  const companySize = co.size?.value || '';
  const funding = co.totalFunding
    ? `${co.totalFunding.currency} ${Math.round(parseInt(co.totalFunding.amount) / 1000000)}M`
    : '';

  // Classify
  const remote = job.remoteOnly ? 'Yes' : 'No';
  const status = classifyLocation(locations, job.remoteOnly);

  // Build URL
  const url = `https://app.welcometothejungle.com/jobs/${job.externalId}`;

  items.push({
    json: {
      'Date Received': dateReceived,
      'Company': co.name || '',
      'Job Title': job.title || '',
      'URL': url,
      'Location': locations,
      'Remote': remote,
      'Salary': salary,
      'Experience': experience,
      'Technologies': technologies,
      'Function': [job.function?.value, job.subFunction?.value].filter(Boolean).join(' \u2192 '),
      'Company Size': companySize,
      'Funding': funding,
      'Status': status,
      'Source': 'graphql',
      'Job ID': job.externalId,
      'Apply URL': job.originalUrl || '',
      'Progress': 'new',
      'Applied': ''
    }
  });
}

if (items.length === 0) {
  items.push({
    json: {
      'Date Received': dateReceived,
      'Company': '⚠ NO JOBS PROCESSED',
      'Job Title': 'All job detail fetches failed',
      'URL': '', 'Location': '', 'Remote': '', 'Salary': '', 'Experience': '',
      'Technologies': '', 'Function': '', 'Company Size': '', 'Funding': '',
      'Status': 'Error',
      'Source': 'graphql',
      'Job ID': '',
      'Apply URL': '',
      'Progress': '',
      'Applied': ''
    }
  });
}

return items;

// Filter out jobs that already exist in the Google Sheet (dedup by URL)
const items = $input.all();
let existingUrls;

try {
  const existingRows = $('Read Existing Jobs').all();
  existingUrls = new Set(
    existingRows.map(row => (row.json['URL'] || '').trim()).filter(u => u.length > 0)
  );
} catch (e) {
  // Read failed — pass everything through (better duplicates than lost data)
  return items;
}

const newItems = [];
let skippedCount = 0;

for (const item of items) {
  const url = (item.json['URL'] || '').trim();
  const status = item.json['Status'] || '';

  // Always pass through error/diagnostic items
  if (!url || status === 'AUTH_EXPIRED' || status === 'Error') {
    newItems.push(item);
    continue;
  }

  if (existingUrls.has(url)) {
    skippedCount++;
    continue;
  }

  newItems.push(item);
}

if (skippedCount > 0) {
  console.log(`Dedup: skipped ${skippedCount} duplicate(s), passing ${newItems.length} new item(s).`);
}

return newItems;
